var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NONAME","text":{"KOREA":"추워... 추워요.","JPN":"寒い……寒いよ。","ENG":"I'm cold... So cold.","TWN":"好冷……好冷。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NONAME","text":{"KOREA":"난... 흉측한 괴물이 되고 싶지 않아.","JPN":"私は……醜い化け物になりたくない。","ENG":"I... I don't want to become a hideous monster.","TWN":"我……不想變成醜陋的怪物。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NONAME","text":{"KOREA":"날... 언니를... 집으로 보내줘요, 모르스.","JPN":"私を……お姉ちゃんを……家に帰してください、モールス。","ENG":"Please... send my sister... home, Mors.","TWN":"請把我……把姐姐……送回家吧，莫爾斯。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신은 이번에도 구하지 못했군요.","JPN":"あなたは今回も救えなかったのですね。","ENG":"You couldn't save her this time either.","TWN":"你這次也沒能拯救她。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아무도.","JPN":"誰も。","ENG":"Anyone.","TWN":"誰都無法。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온...! 또 도망치려는 건가!","JPN":"タギリオン……！　また逃げるのか！","ENG":"Thagirion...! Are you trying to run away again?!","TWN":"塔基里翁……！又打算逃走嗎！"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"왜, 나를 영멸시키지 않지? 난 포기하지 않는다! 네놈이 어디로 가든, 기필코 그 계획을 막을 것이다!!","JPN":"なぜ我を永滅させない？　我は諦めない！　貴様がどこに行こうが、必ず貴様の計画を阻止する！","ENG":"Why won't you annihilate me? I will not give up! Wherever you go, I will stop your plan, no matter what!!","TWN":"為什麼不徹底毀滅我？我不會放棄！無論你逃到哪裡，我一定會阻止你的計畫！！"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...상관없어요.","JPN":"……構いません。","ENG":"...It doesn't matter.","TWN":"……無所謂。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"어차피 또, 실패할 테니까.","JPN":"どうせまた、失敗するでしょうから。","ENG":"You'll fail again anyway.","TWN":"反正你還是會失敗。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_03","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신은 나무에 매달린 썩은 열매.","JPN":"あなたは木に成った、腐った実。","ENG":"You are the rotten fruit hanging from a tree.","TWN":"你就像掛在樹上的腐爛果實。"},"stage":{"bg":"CASTLE_03","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"내가 따지 않아도, 때가 되면 알아서 떨어져 나가겠죠.","JPN":"私が摘み取らなくても、その時になれば勝手に落ちるでしょう。","ENG":"Even if I don't pluck you, you'll fall on your own when the time comes.","TWN":"即使我不摘取，時候到了也會自行墜落。"},"stage":{"bg":"CASTLE_03","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"...미안하다, 아우드라.","JPN":"……すまない、アウドラ。","ENG":"...I'm sorry, Audra.","TWN":"……對不起，奧德拉。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이번에도... 널 구하지 못했구나.","JPN":"今回も……そなたを助けられなかった。","ENG":"Once again... I couldn't save you.","TWN":"這一次……我還是沒能救你。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"갑옷에 유폐된 몸으로 발버둥치며, 너의 경멸 어린 기만에 농락 당할 뿐.","JPN":"鎧に幽閉された体であがき、そなたの軽蔑めいた欺瞞に翻弄されるのみ。","ENG":"Trapped within this armor, I can do nothing but struggle and be toyed with by your scornful deception.","TWN":"只能在被鎧甲囚禁的身軀中掙扎，任由你輕蔑欺瞞戲弄。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하지만... 이것 하나만은 약속하마.","JPN":"だが……これだけは約束しよう。","ENG":"But... there is one thing I can promise you.","TWN":"但是……我只會向你承諾一件事。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네가 나의 실패에 질려 도망치는 한이 있더라도, 난 너를 포기하지 않을 것임을.","JPN":"そなたが我の失敗に嫌気がさし逃げたとしても、我はそなたを諦めない。","ENG":"Even if you grow weary of my failures and flee from me, I will never give up on you.","TWN":"即使你厭倦我的失敗而逃離，我也絕不會放棄你。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"꿈을 꿨나?","JPN":"夢を見ていたのか？","ENG":"Did you have a dream?","TWN":"我做夢了嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그대는...?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"아!","JPN":"あ！","ENG":"Ah!","TWN":"啊！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"감옥은...? 그녀의 자매는 어디로 사라졌사옵니까?","JPN":"牢屋は……？　彼女の姉妹はどこに消えたのでございますか？","ENG":"The prison...? Where did her sister go?","TWN":"監獄呢……？她的姐妹去哪了？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"우리가 도망쳐왔어. 클라라에게 도움을 받았거든.","JPN":"私たち脱走したんだ。クララに助けてもらってね。","ENG":"We escaped. Clara helped us.","TWN":"多虧克拉拉幫忙，我們逃出來了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"도망...?","JPN":"脱走……？","ENG":"Escaped...?","TWN":"逃……？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"하지만, 잠결에 어떤 연주를 들은 것 같사온데...","JPN":"ですが、夢うつつに何かの演奏が聞こえましたが……","ENG":"But... I feel as though I heard some kind of performance in my sleep...","TWN":"不過，我在半夢半醒間，似乎聽見了某種演奏……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"합주가 있었어. 낙원에서 엘리시움 필하모닉의 단원들을 만났거든.","JPN":"合奏をしたんだ。楽園でエリシウムフィルハーモニーの団員に会ってね。","ENG":"There was an ensemble. We met members of Elysium Philharmonic in the Promised Land.","TWN":"那是合奏，我們在樂園遇見了愛樂組織的成員。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"설마, 마에스트로?","JPN":"まさか、マエストロ？","ENG":"You mean... Maestra?","TWN":"難道是指揮家？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...맞아. 내가 그녀의 기억을 이용했어.","JPN":"……そう。私が彼女の記憶を利用したの。","ENG":"...That's right. I used her memories.","TWN":"……沒錯。我利用了她的記憶。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이번엔, 누군가를 희생시키는 연주가 아니었네.","JPN":"だが今回は、誰かを犠牲にする演奏ではなかった。","ENG":"But this time, it wasn't a performance that sacrificed anyone.","TWN":"但這次，並不是需要犧牲某人的演奏。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오히려 그녀의 연주가, 낙원의 위협으로부터 사람들을 지켜냈지.","JPN":"むしろ彼女の演奏が、楽園の脅威から人々を守ったのさ。","ENG":"Rather, her performance protected people from the threat of the Promised Land.","TWN":"反而她的音樂，守護眾人免於樂園的威脅。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}}]`);export{e as default};